import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Project Introduction","description":"An unofficial handbook of study and campus life information co-maintained by SCUT students","frontmatter":{"lang":"en-US","title":"Project Introduction","description":"An unofficial handbook of study and campus life information co-maintained by SCUT students","llm_translated":true},"headers":[],"relativePath":"en/introduction.md","filePath":"en/introduction.md","lastUpdated":1784829332000}`),a={name:`en/introduction.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/introduction.md for this page in Markdown format</div><h1 id="what-is-this-handbook" tabindex="-1">What Is This Handbook <a class="header-anchor" href="#what-is-this-handbook" aria-label="Permalink to “What Is This Handbook”">​</a></h1><p>Survive in SCUT is an unofficial information guide co-written by students, covering study and campus life scenarios at SCUT. It consolidates information scattered across notices, regulations, personal experiences, and daily campus life, reducing the cost of repeated searching, trial and error for both freshmen and current students.</p><p>This handbook offers <strong>information and experience</strong>, not official university documents, nor does it make decisions for you. For matters concerning enrollment status, academic plans, scholarships and grants, medical care, and safety, always refer to the latest regulations issued by the university and relevant departments.</p><h2 id="who-it-s-for" tabindex="-1">Who It&#39;s For <a class="header-anchor" href="#who-it-s-for" aria-label="Permalink to “Who It&#39;s For”">​</a></h2><ul><li>Those preparing to apply or about to enroll, who want a realistic preview of campus life;</li><li>Current students who need to look up information on courses, facilities, campus services, further education, and health;</li><li>Contributors willing to share firsthand experiences, verify rules, or correct outdated information.</li></ul><p>Policies may vary across different schools, majors, years, and campuses. Personal experience can help narrow the information gap, but it cannot replace the official notices that apply to your specific situation.</p><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use”">​</a></h2><ol><li><strong>Search for your specific question first.</strong> Use the search bar at the top of the page to enter a course name, campus, service, or keyword. No need to read through everything from start to finish.</li><li><strong>Check the date and source.</strong> Prioritize content that includes a clear year, scope of applicability, and source. Be cautious when this information is missing.</li><li><strong>Confirm with official sources.</strong> For matters that directly affect your outcome — application requirements, deadlines, document lists, grade calculations — double-check with the university website, academic affairs system, or the responsible department.</li><li><strong>Treat experiences as options.</strong> The handbook tells you how others have handled a problem; the final choice still depends on your own goals, circumstances, and risk tolerance.</li></ol><h2 id="what-content-may-be-outdated" tabindex="-1">What Content May Be Outdated <a class="header-anchor" href="#what-content-may-be-outdated" aria-label="Permalink to “What Content May Be Outdated”">​</a></h2><p>The following information changes relatively quickly and should not be used independently of its publication date:</p><ul><li>Freshman registration dates, entry points, required documents, and pickup arrangements;</li><li>Operating hours for campus buses, gates, venues, cafeterias, and service points;</li><li>Rules for major changes, graduate exemptions, awards and evaluations, comprehensive assessments, and academic plans;</li><li>Campus clinic visits, referrals, medical insurance, and reimbursement procedures;</li><li>Nearby off-campus businesses, prices, transit routes, and contact information.</li></ul><p>If a page does not indicate when it was last verified, it defaults to representing the situation only at the time of writing. When you find content that no longer matches reality, defer to the latest official notices — and feel free to correct it.</p><h2 id="how-to-contribute" tabindex="-1">How to Contribute <a class="header-anchor" href="#how-to-contribute" aria-label="Permalink to “How to Contribute”">​</a></h2><p>You don&#39;t need to understand the entire project to contribute. One typo fix, a source supplement, a firsthand account of a process, or a flag for outdated information can reduce the trial-and-error costs for those who come after you.</p><ul><li>Click &quot;Edit this page&quot; at the bottom of any page to submit a change directly;</li><li>Submit an Issue on GitHub, describing the problem, scope of applicability, and information source;</li><li>Read the <a href="/en/others/contributing.html">Contribution Guide</a> and <a href="/en/others/todo.html">TODO Summary</a> to claim content that still needs work.</li></ul><p>When contributing factual content, try to specify the <strong>applicable campus, school or audience, verification date, and information source</strong>. The value of this handbook is not in sounding authoritative, but in making information verifiable, correctable, and passable to others.</p>`,17)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};